ref:
state s = 0;
label s;
row {
  button "+2" { s = s + 2; }
  button "+3" { s = s + 3; }
}

state f = 1;
label f;
row {
  button "up" { f = f + 1; }
  button "down" { if f > 1 { f = f - 1; } }
}

state l = 0;
state d = 0;
row {
  button "like" { l = l + 1; }
  button "dislike" { d = d + 1; }
}
label "Likes: " + l;
label "Dislikes: " + d;

state dark = false;
row {
  button "dark" { dark = true; }
  button "light" { dark = false; }
}
if dark { label "DARK MODE"; }

state n = 64;
label n;
button "half" { n = n / 2; }

state p = 0;
label p;
button "+25" { p = p + 25; }
if p >= 100 { label "complete"; }

state s = "";
input s;
label "NAME: " + s;

state a = true;
button "switch" { if a { a = false; } else { a = true; } }
if a { label "mode A"; } else { label "mode B"; }

state n = 0;
label n;
button "+4" { if n < 10 { n = n + 4; } }

state a = 0;
state b = 0;
state c = 0;
row {
  button "a+" { a = a + 1; }
  button "b+" { b = b + 1; }
  button "c+" { c = c + 1; }
}
label a + b + c;

state s = "";
input s;
if s == "" { label "type something"; }

state n = 0;
label n;
button "step" { n = n * 2 + 1; }

state t = 20;
label t + "°";
row {
  button "warmer" { t = t + 1; }
  button "cooler" { t = t - 1; }
}

state a = 0;
state p = 0;
label "Apples: " + a;
label "Pears: " + p;
row {
  button "add apple" { a = a + 1; }
  button "add pear" { p = p + 1; }
}

state c = 0;
button "unlock" { c = c + 1; }
if c >= 3 { label "OPEN"; }

state s = "";
input s;
label s;
button "clear" { s = ""; }
